

class Solution(object):
    def isSubsequence(self, s, t):
        """
        :type s: str
        :type t: str
        :rtype: bool
        """
        # find all the characters of s in t
        candidates = []
        for v in t:
            if v in s:
                candidates.append(v)
        
        idx, output = 0, ""
        while idx < len(s):
            # if candidates is less than idx
		    # if candidates is less than len(s)
		    # ==> candidates is not a subsequence of s
            if len(candidates) < idx:
                break
            if len(candidates) < len(s):
                break

            # condition 1:
            # s=abc,t=cabc
            # ==> skip c, so remove c from candidates
            if idx == 0 and s[idx] != candidates[idx]:
                candidates.remove(candidates[idx])
                continue

            		
            # suitable condition:
            # s=abc,t=abc
            # ==> add a to output, so remove a from candidates
            # ------
            # condition 2: (else if part)
            # s=abc,t=abbc
            # ==> skip b, so remove b from candidates
            # ------
            # condition 3:
            # s=abc,t=acb
            # ==> not suitable, so break
            if s[idx] == candidates[idx]:
                output += candidates[idx]
                idx += 1
                continue
            elif idx > 0 and candidates[idx] == s[idx-1]:
                candidates.remove(candidates[idx])
                continue
            elif len(candidates) >= len(s):
                idx, output = 0, ""
                candidates = candidates[idx+1:]
                continue
            else:
                break

        return output == s

cases = {
    ("abc", "ahbgdc"): True,
    ("axc", "ahbgdc"): False,
    ("leeeeetcode",""): True,
    ("rjufvjafbxnbgriwgokdgqdqewn", ""): False
}

for k, v in cases.items():
    s, t = k
    solution = Solution()
    print(solution.isSubsequence(s, t) == v)